import{z as e}from"zod";export const FatigueTermSchema=e.object({term:e.string().min(1),suggestion:e.string().min(1),severity:e.enum(["high","medium","low"]),category:e.string().min(1)}),ClichePatternSchema=e.object({id:e.string().min(1),description:e.string().min(1),severity:e.enum(["high","medium","low"]),suggestion:e.string().min(1),thresholdPer1k:e.number().min(0)}),SynonymGroupSchema=e.object({id:e.string().min(1),description:e.string().min(1),terms:e.array(e.string().min(1)).min(2)}),StyleIssueSchema=e.object({category:e.enum(["fatigue","cliche","pattern","burstiness","parallelism","synonym"]),severity:e.enum(["high","medium","low"]),match:e.string(),offset:e.number().int().min(0),length:e.number().int().min(1),suggestion:e.string(),context:e.string(),label:e.string().optional()}),StyleReportSchema=e.object({issues:e.array(StyleIssueSchema),score:e.number().min(0).max(100),fatigueCount:e.number().int().min(0),clicheCount:e.number().int().min(0),patternCount:e.number().int().min(0),summary:e.string()}),BurstinessResultSchema=e.object({score:e.number().min(0).max(100),label:e.string(),issues:e.array(StyleIssueSchema)});
